     6→/** Class that represented parsing errors. */
     7→class ParseException extends RuntimeException {
     8→  ParseException(String s) { super(s); }
     9→  ParseException(Throwable t) { super(t); }
    10→}
    11→
    12→class Parser {
    13→  
    14→  private Lexer in;
    15→  
    16→  Parser(Lexer i) { in = i; }
    17→  
    18→  Parser(Reader inputStream) { this(new Lexer(inputStream)); }
    19→  
    20→  Parser(String fileName) throws IOException { this(new FileReader(fileName)); }
    21→  
    22→  Lexer lexer() { return in; }
    23→  
    24→  public void initParser() { }
    25→  
    26→  /** Parses the program in the Lexer associated with this. */
    27→  public AST parse() throws ParseException {
    28→    try {
    29→      in.reset();
    30→      AST prog = parseExp();
    31→      Token t = in.readToken();
    32→      if (t == EndOfFile.ONLY) return prog;
    33→      else throw new ParseException("Legal program followed by extra token " + t);
    34→    } 
    35→    finally {
    36→      try { in.rdr.close(); } 
    37→      catch (IOException e) { throw new ParseException(e); }
    38→    }
    39→  }
    40→  
    41→  /** Parses and syntactically checks the program in the Lexer associated with this. */
    42→  public AST parseAndCheck() throws ParseException {
    43→    AST prog = parseExp();
    44→    Token t = in.readToken();
    45→    if (t != EndOfFile.ONLY) throw new ParseException("Legal program '" + prog + "'followed by extra token " + t);
    46→    
    47→    /* Invoke the CheckVisitor confirm prog does not contain free variables or parameter lists with duplicate names. */
    48→    prog.accept(CheckVisitor.INITIAL);   // aborts on an error by throwing an exception
    49→    return prog;
    50→  }
    51→  
    52→  /** Parses:
    53→    *   <exp> :: = if <exp> then <exp> else <exp>
    54→    *            | let <prop-def-list> in <exp>
    55→    *            | map <id-list> to <exp>
    56→    *            | <term> { <biop> <term> }*  // (left associatively!)
    57→    */
    58→  private AST parseExp() {
    59→    Token token = in.readToken();
    60→    
    61→    if (token == Lexer.IF) return parseIf();
    62→//    if (token == Lexer.LETREC) return parseLetRec();  // supports addition of letrec
    63→    if (token == Lexer.LET) return parseLet();
    64→    if (token == Lexer.MAP) return parseMap();
    65→    
    66→    /*  Supports the addition of blocks to Jam */
    67→    if (token == LeftBrace.ONLY) {
    68→      AST[] exps = parseExps(SemiColon.ONLY, RightBrace.ONLY);
    69→      // including closing brace
    70→      if (exps.length == 0) throw new ParseException("Illegal empty block");
    71→      return new Block(exps);
    72→    }
    73→    
    74→    /* phrase begin with a term */
    75→    AST exp = parseTerm(token);
    76→    
    77→    Token next = in.peek();
    78→    while (next instanceof OpToken) {
    79→      OpToken op = (OpToken) next;
    80→      in.readToken(); // remove next from input stream
    81→      if (! (op.isBinOp())) error(next, "binary operator");
    82→      AST newTerm = parseTerm(in.readToken());
    83→      exp = new BinOpApp(op.toBinOp(), exp, newTerm);
    84→//      System.err.println("exp updated to: " + exp);
    85→      next = in.peek();
    86→    }
    87→//    System.err.println("parseTerm returning " + exp);
    88→    return exp;
    89→  }
    90→  
    91→  /** Parses:
    92→    *   <term>     ::= { <unop> } <term> | <constant> | <factor> {( <exp-list> )}
    93→    *   <constant> ::= <null> | <int> | <bool>
    94→    * @param token   first token in input stream to be parsed; remainder in Lexer named in.
    95→    */
    96→  private AST parseTerm(Token token) {
    97→    
    98→    if (token instanceof OpToken) {
    99→      OpToken op = (OpToken) token;
   100→      if (! op.isUnOp()) error(op,"unary operator");
   101→      return new UnOpApp(op.toUnOp(), parseTerm(in.readToken()));
   102→    }
   103→    
   104→    if (token instanceof Constant) return (Constant) token;
   105→    
   106→    AST factor = parseFactor(token);
   107→    Token next = in.peek();
   108→    if (next == LeftParen.ONLY) {
   109→      in.readToken();  // remove next from input stream
   110→      AST[] exps = parseArgs();  // including closing paren
   111→      return new App(factor,exps);
   112→    }
   113→    return factor;
   114→  }
   115→  
   116→  /** Parses:  <factor>   ::= <prim> | <variable> | ( <exp> )
   117→    * @param token   first token in input stream to be parsed; remainder in Lexer named in.
   118→    */
   119→  private AST parseFactor(Token token) {
   120→    
   121→    if (token == LeftParen.ONLY) { 
   122→      /* Parse a parenthesized expression */
   123→      AST exp = parseExp();
   124→      token = in.readToken();
   125→      if (token != RightParen.ONLY) error(token,"`)'");
   126→      return exp;
   127→    }
   128→    
   129→    if (! (token instanceof PrimFun) && ! (token instanceof Variable))
   130→      error(token,"constant, primitive, variable, or `('");
   131→    
   132→    // Term = Variable or PrimFun       
   133→    return (Term) token;
   134→  }      
