/** Interface for Jam types. */
interface JamType {
  boolean equals(Object other);
  String toString();
}

/** Singleton class for the integer type. */
class IntType implements JamType {
  public static final IntType ONLY = new IntType();
  private IntType() {}
  public boolean equals(Object o) { return o instanceof IntType; }
  public int hashCode() { return 1; }
  public String toString() { return "int"; }
}

/** Singleton class for the boolean type. */
class BoolType implements JamType {
  public static final BoolType ONLY = new BoolType();
  private BoolType() {}
  public boolean equals(Object o) { return o instanceof BoolType; }
  public int hashCode() { return 2; }
  public String toString() { return "bool"; }
}

/** Singleton class for the unit type. */
class UnitType implements JamType {
  public static final UnitType ONLY = new UnitType();
  private UnitType() {}
  public boolean equals(Object o) { return o instanceof UnitType; }
  public int hashCode() { return 3; }
  public String toString() { return "unit"; }
}

/** Class for list types: list elemType. */
class ListType implements JamType {
  private JamType elemType;
  ListType(JamType t) { elemType = t; }
  public JamType elemType() { return elemType; }
  public boolean equals(Object o) {
    if (!(o instanceof ListType)) return false;
    return elemType.equals(((ListType) o).elemType);
  }
  public int hashCode() { return 7 + elemType.hashCode(); }
  public String toString() { return "list " + elemType; }
}

/** Class for reference types: ref elemType. */
class RefType implements JamType {
  private JamType elemType;
  RefType(JamType t) { elemType = t; }
  public JamType elemType() { return elemType; }
  public boolean equals(Object o) {
    if (!(o instanceof RefType)) return false;
    return elemType.equals(((RefType) o).elemType);
  }
  public int hashCode() { return 11 + elemType.hashCode(); }
  public String toString() { return "ref " + elemType; }
}

/** Class for function types: (params -> result). */
class FunType implements JamType {
  private JamType[] params;
  private JamType result;
  FunType(JamType[] p, JamType r) { params = p; result = r; }
  public JamType[] params() { return params; }
  public JamType result() { return result; }
  public boolean equals(Object o) {
    if (!(o instanceof FunType)) return false;
    FunType f = (FunType) o;
    if (params.length != f.params.length) return false;
    for (int i = 0; i < params.length; i++) {
      if (!params[i].equals(f.params[i])) return false;
    }
    return result.equals(f.result);
  }
  public int hashCode() {
    int h = result.hashCode();
    for (JamType p : params) h = 31 * h + p.hashCode();
    return h;
  }
  public String toString() {
    return "(" + ToString.toString(params, ", ") + " -> " + result + ")";
  }
}

