/** Parser for Typed Jam (Assignment 5).
  * Key changes from Assignment 4:
  *  - Definitions and map parameters require type annotations: Id : Type
  *  - empty must be followed by : Type
  *  - PrimFun must be applied (can no longer appear standalone)
  *  - Removed primitives: list?, number?, function?, ref?, arity
  *  - Added type grammar: unit | int | bool | list Type | ref Type | (TypeList -> Type)
  */

import java.io.*;
import java.util.*;

/** Class that represents parsing errors. */
class ParseException extends RuntimeException {
  ParseException(String s) { super(s); }
  ParseException(Throwable t) { super(t); }
}

/** Helper pair class for a typed variable (variable + type). */
class TypedVarPair {
  Variable[] vars;
  JamType[] types;
  TypedVarPair(Variable[] v, JamType[] t) { vars = v; types = t; }
}

class Parser {

  private Lexer in;

  Parser(Lexer i) { in = i; }

  Parser(Reader inputStream) { this(new Lexer(inputStream)); }

  Parser(String fileName) throws IOException { this(new FileReader(fileName)); }

  Lexer lexer() { return in; }

  public void initParser() { }

  /** Parses the program in the Lexer associated with this. */
  public AST parse() throws ParseException {
    try {
      in.reset();
      AST prog = parseExp();
      Token t = in.readToken();
      if (t == EndOfFile.ONLY) return prog;
      else throw new ParseException("Legal program followed by extra token " + t);
    }
    finally {
      try { in.rdr.close(); }
      catch (IOException e) { throw new ParseException(e); }
    }
  }

  /** Parses and syntactically checks the program in the Lexer associated with this. */
  public AST parseAndCheck() throws ParseException {
    AST prog = parseExp();
    Token t = in.readToken();
    if (t != EndOfFile.ONLY) throw new ParseException("Legal program '" + prog + "'followed by extra token " + t);

    /* Invoke the CheckVisitor to confirm prog does not contain free variables or duplicate names. */
    prog.accept(CheckVisitor.INITIAL);   // aborts on an error by throwing an exception
    return prog;
  }

  /** Parses:
    *   <exp> ::= if <exp> then <exp> else <exp>
    *           | let <prop-def-list> in <exp>
    *           | map TypedIdList to <exp>
    *           | { PropStatementList }
    *           | <term> { <binop> <term> }*
    */
  private AST parseExp() {
    Token token = in.readToken();

    if (token == Lexer.IF) return parseIf();
    if (token == Lexer.LET) return parseLet();
    if (token == Lexer.MAP) return parseMap();

    /* Supports the addition of blocks to Jam */
    if (token == LeftBrace.ONLY) {
      AST[] exps = parseExps(SemiColon.ONLY, RightBrace.ONLY);
      if (exps.length == 0) throw new ParseException("Illegal empty block");
      return new Block(exps);
    }

    /* phrase begins with a term */
    AST exp = parseTerm(token);

    Token next = in.peek();
    while (next instanceof OpToken) {
      OpToken op = (OpToken) next;
      in.readToken(); // remove next from input stream
      if (! (op.isBinOp())) error(next, "binary operator");
      AST newTerm = parseTerm(in.readToken());
      exp = new BinOpApp(op.toBinOp(), exp, newTerm);
      next = in.peek();
    }
    return exp;
  }

  /** Parses a term in the typed grammar:
    *   <term> ::= <unop> <term>
    *            | Prim ( <exp-list> )        -- primitive applied to args
    *            | empty : Type               -- typed empty list
    *            | <factor> { ( <exp-list> ) } -- optional application
    *            | <int>
    *            | <bool>
    */
  private AST parseTerm(Token token) {

    /* Unary operator */
    if (token instanceof OpToken) {
      OpToken op = (OpToken) token;
      if (! op.isUnOp()) error(op, "unary operator");
      return new UnOpApp(op.toUnOp(), parseTerm(in.readToken()));
    }

    /* Typed empty: empty : Type */
    if (token == EmptyConstant.ONLY) {
      Token colon = in.readToken();
      if (colon != Colon.ONLY) error(colon, "`:' after `empty'");
      JamType elemType = parseType();
      return new EmptyConstant(elemType);
    }

    /* Primitive function must be applied: Prim ( ExpList ) */
    if (token instanceof PrimFun) {
      PrimFun prim = (PrimFun) token;
      // Check for disallowed primitives
      if (prim == FunctionPPrim.ONLY || prim == NumberPPrim.ONLY ||
          prim == ListPPrim.ONLY     || prim == RefPPrim.ONLY    ||
          prim == ArityPrim.ONLY) {
        throw new ParseException("Primitive `" + prim + "' is not supported in Typed Jam");
      }
      // Allowed prims: cons, first, rest, empty?, cons?
      Token next = in.readToken();
      if (next != LeftParen.ONLY) error(next, "`(' after primitive `" + prim + "'");
      AST[] args = parseArgs();  // includes closing paren
      return new App(prim, args);
    }

    /* Integer or boolean constant */
    if (token instanceof Constant) return (Constant) token;

    /* Factor optionally followed by application */
    AST factor = parseFactor(token);
    Token next = in.peek();
    if (next == LeftParen.ONLY) {
      in.readToken();  // consume '('
      AST[] exps = parseArgs();  // includes closing paren
      return new App(factor, exps);
    }
    return factor;
  }

  /** Parses: <factor> ::= ( <exp> ) | Id
    * Note: PrimFun is NOT a valid Factor in Typed Jam; it must be applied in parseTerm.
    */
  private AST parseFactor(Token token) {

    if (token == LeftParen.ONLY) {
      AST exp = parseExp();
      Token t = in.readToken();
      if (t != RightParen.ONLY) error(t, "`)'");
      return exp;
    }

    if (token instanceof Variable) return (Variable) token;

    error(token, "variable or `('");
    return null; // unreachable
  }

  /** Parses `if <exp> then <exp> else <exp>' given that `if' has already been read. */
  private AST parseIf() {
    AST test = parseExp();
    Token key1 = in.readToken();
    if (key1 != Lexer.THEN) error(key1, "`then'");
    AST conseq = parseExp();
    Token key2 = in.readToken();
    if (key2 != Lexer.ELSE) error(key2, "`else'");
    AST alt = parseExp();
    return new If(test, conseq, alt);
  }

  /** Parses `let <prop-def-list> in <exp>' given that `let' has already been read. */
  private AST parseLet() {
    Def[] defs = parseDefs();
    AST body = parseExp();
    return new Let(defs, body);
  }

  /** Parses `map TypedIdList to <exp>' given that `map' has already been read. */
  private AST parseMap() {
    TypedVarPair tvp = parseTypedVars();  // reads up to and including `to'
    AST body = parseExp();
    return new Map(tvp.vars, tvp.types, body);
  }

  /** Parses a comma-or-semicolon separated list of expressions followed by a delimiter.
    *   <exp-list> ::= <empty> | <prop-exp-list>
    *   <prop-exp-list> ::= <exp> | <exp> sep <prop-exp-list>
    */
  private AST[] parseExps(Token separator, Token delim) {
    LinkedList<AST> exps = new LinkedList<AST>();
    Token next = in.peek();

    if (next == delim) {
      in.readToken(); // consume delimiter
      return new AST[0];
    }

    do {
      AST exp = parseExp();
      exps.addLast(exp);
      next = in.readToken();
    } while (next == separator);

    if (next != delim) error(next, "`,' or `)'");
    return (AST[]) exps.toArray(new AST[0]);
  }

  private AST[] parseArgs() { return parseExps(Comma.ONLY, RightParen.ONLY); }

  /** Parses typed parameter list for `map':
    *   TypedIdList ::= { PropTypedIdList }
    *   PropTypedIdList ::= TypedId | TypedId, PropTypedIdList
    *   TypedId ::= Id : Type
    * NOTE: consumes `to' following the list.
    */
  private TypedVarPair parseTypedVars() {
    LinkedList<Variable> vars = new LinkedList<Variable>();
    LinkedList<JamType> types = new LinkedList<JamType>();

    Token t = in.readToken();
    if (t == Lexer.TO) {
      // empty param list
      return new TypedVarPair(new Variable[0], new JamType[0]);
    }

    do {
      if (! (t instanceof Variable)) error(t, "variable");
      Variable v = (Variable) t;

      Token colon = in.readToken();
      if (colon != Colon.ONLY) error(colon, "`:' after variable name");

      JamType typ = parseType();
      vars.addLast(v);
      types.addLast(typ);

      t = in.readToken();
      if (t == Lexer.TO) break;
      if (t != Comma.ONLY) error(t, "`to' or `,'");
      t = in.readToken();
    } while (true);

    return new TypedVarPair(
      vars.toArray(new Variable[0]),
      types.toArray(new JamType[0])
    );
  }

  /** Parses a proper (non-empty) list of definitions:
    *   prop-def-list ::= def | def prop-def-list
    *   def ::= Id : Type := Exp ;
    * NOTE: consumes `in' following the definitions.
    */
  private Def[] parseDefs() {
    LinkedList<Def> defs = new LinkedList<Def>();
    Token t = in.readToken();

    do {
      Def d = parseDef(t);
      defs.addLast(d);
      t = in.readToken();
    } while (t != Lexer.IN);

    return (Def[]) defs.toArray(new Def[0]);
  }

  /** Parses `Id : Type := Exp ;' given that the first token (Id) has been read. */
  private Def parseDef(Token var) {
    if (! (var instanceof Variable)) error(var, "variable");
    Variable v = (Variable) var;

    Token colon = in.readToken();
    if (colon != Colon.ONLY) error(colon, "`:' after variable name");

    JamType typ = parseType();

    Token bind = in.readToken();
    if (bind != Lexer.BIND) error(bind, "`:='");

    AST exp = parseExp();

    Token semi = in.readToken();
    if (semi != SemiColon.ONLY) error(semi, "`;'");

    return new Def(v, typ, exp);
  }

  /** Parses a Type:
    *   Type ::= unit | int | bool | list Type | ref Type | (TypeList -> Type)
    */
  private JamType parseType() {
    Token t = in.readToken();

    if (t == Lexer.UNIT_TYPE) return UnitType.ONLY;
    if (t == Lexer.INT_TYPE)  return IntType.ONLY;
    if (t == Lexer.BOOL_TYPE) return BoolType.ONLY;

    if (t == Lexer.LIST_TYPE) {
      JamType elem = parseType();
      return new ListType(elem);
    }

    if (t == Lexer.REF) {
      JamType elem = parseType();
      return new RefType(elem);
    }

    if (t == LeftParen.ONLY) {
      // (TypeList -> Type)
      JamType[] params = parseTypeList();  // reads types until '->'
      Token arrow = in.readToken();
      if (arrow != Arrow.ONLY) error(arrow, "`->'");
      JamType result = parseType();
      Token rp = in.readToken();
      if (rp != RightParen.ONLY) error(rp, "`)'");
      return new FunType(params, result);
    }

    error(t, "type (unit, int, bool, list, ref, or `(')");
    return null; // unreachable
  }

  /** Parses a comma-separated list of types, stopping before `->'.
    *   TypeList ::= { PropTypeList }
    *   PropTypeList ::= Type | Type, PropTypeList
    */
  private JamType[] parseTypeList() {
    // If the next token is '->', the type list is empty
    if (in.peek() == Arrow.ONLY) {
      return new JamType[0];
    }
    LinkedList<JamType> types = new LinkedList<JamType>();
    do {
      types.addLast(parseType());
      Token next = in.peek();
      if (next == Arrow.ONLY) break;
      if (next == Comma.ONLY) {
        in.readToken(); // consume ','
      } else {
        error(next, "`,' or `->'");
      }
    } while (true);
    return types.toArray(new JamType[0]);
  }

  private AST error(Token found, String expected) {
    throw new ParseException("Token `" + found + "' appears where " + expected + " was expected");
  }

  /** A legacy "main" method. */
  public static void main(String[] args) throws IOException {
    if (args.length == 0) return;
    Parser p = new Parser(args[0]);
    AST prog = p.parse();
  }
}

/** Typed Jam Interpreter (Assignment 5).
  * Supports two evaluation strategies:
  *   eagerEval() - call-by-value/eager (value/value)
  *   lazyEval()  - call-by-value/lazy  (value/need)
  * Both methods run the parser, context-sensitive syntax checker, type checker, and then evaluate.
  */

import java.io.IOException;
import java.io.Reader;
import java.util.HashMap;

/** Exception thrown when a Jam program has a type error. */
class TypeException extends RuntimeException {
  TypeException(String msg) { super(msg); }
}

/** Exception thrown during Jam evaluation (run-time errors). */
class EvalException extends RuntimeException {
  EvalException(String msg) { super(msg); }
}

/** Interpreter class for Typed Jam. Exposes only eagerEval() and lazyEval(). */
class Interpreter {
  /** Parser to use. */
  Parser parser;

  /** Parsed (and syntax-checked) AST. */
  AST prog;

  Interpreter(String fileName) throws IOException {
    parser = new Parser(fileName);
    prog = parser.parseAndCheck();
  }

  Interpreter(Parser p) {
    parser = p;
    prog = parser.parseAndCheck();
  }

  Interpreter(Reader reader) {
    parser = new Parser(reader);
    prog = parser.parseAndCheck();
  }

  /* ----------------------------------------------------------------
   * Public API
   * ---------------------------------------------------------------- */

  /** Type-checks then evaluates using call-by-value/eager (value/value). */
  public JamVal eagerEval() {
    checkTypes(prog);
    return prog.accept(valueValueVisitor);
  }

  /** Type-checks then evaluates using call-by-value/lazy (value/need). */
  public JamVal lazyEval() {
    checkTypes(prog);
    return prog.accept(valueNeedVisitor);
  }

  /* ----------------------------------------------------------------
   * Type Checker
   * ---------------------------------------------------------------- */

  /** Type-checks the given AST.  Throws TypeException if any type error is found. */
  private void checkTypes(AST ast) {
    ast.accept(new TypeCheckVisitor(new HashMap<Variable, JamType>()));
  }

  /** Visitor that type-checks a Typed Jam AST.  Returns the type of each expression. */
  static class TypeCheckVisitor implements ASTVisitor<JamType> {

    /** Type environment: maps variables to their declared types. */
    private HashMap<Variable, JamType> env;

    TypeCheckVisitor(HashMap<Variable, JamType> e) { env = e; }

    /** Returns a new TypeCheckVisitor with vars[i] -> types[i] added. */
    private TypeCheckVisitor extend(Variable[] vars, JamType[] types) {
      HashMap<Variable, JamType> newEnv = new HashMap<Variable, JamType>(env);
      for (int i = 0; i < vars.length; i++) {
        newEnv.put(vars[i], types[i]);
      }
      return new TypeCheckVisitor(newEnv);
    }

    /* ----- Visitor methods ----- */

    public JamType forIntConstant(IntConstant i) { return IntType.ONLY; }

    public JamType forBoolConstant(BoolConstant b) { return BoolType.ONLY; }

    /** Typed empty: empty : ElemType has type list ElemType. */
    public JamType forEmptyConstant(EmptyConstant n) {
      JamType elem = n.elemType();
      if (elem == null)
        throw new TypeException("empty must have a type annotation in Typed Jam");
      return new ListType(elem);
    }

    public JamType forVariable(Variable v) {
      JamType t = env.get(v);
      if (t == null)
        throw new TypeException("Unbound variable " + v);
      return t;
    }

    /** PrimFun as a standalone expression is illegal in Typed Jam. */
    public JamType forPrimFun(PrimFun f) {
      throw new TypeException("Primitive `" + f + "' cannot be used as a standalone value");
    }

    public JamType forUnOpApp(UnOpApp u) {
      final JamType argType = u.arg().accept(this);
      return u.rator().accept(new UnOpVisitor<JamType>() {
        public JamType forUnOpPlus() {
          if (!(argType instanceof IntType))
            throw new TypeException("Unary + requires int, got " + argType);
          return IntType.ONLY;
        }
        public JamType forUnOpMinus() {
          if (!(argType instanceof IntType))
            throw new TypeException("Unary - requires int, got " + argType);
          return IntType.ONLY;
        }
        public JamType forOpTilde() {
          if (!(argType instanceof BoolType))
            throw new TypeException("~ requires bool, got " + argType);
          return BoolType.ONLY;
        }
        public JamType forOpBang() {
          if (!(argType instanceof RefType))
            throw new TypeException("! requires a ref type, got " + argType);
          return ((RefType) argType).elemType();
        }
        public JamType forOpRef() {
          return new RefType(argType);
        }
      });
    }

    public JamType forBinOpApp(BinOpApp b) {
      final JamType t1 = b.arg1().accept(this);
      final JamType t2 = b.arg2().accept(this);
      return b.rator().accept(new BinOpVisitor<JamType>() {
        public JamType forBinOpPlus()  { checkBothInt(t1, t2, "+");  return IntType.ONLY; }
        public JamType forBinOpMinus() { checkBothInt(t1, t2, "-");  return IntType.ONLY; }
        public JamType forOpTimes()    { checkBothInt(t1, t2, "*");  return IntType.ONLY; }
        public JamType forOpDivide()   { checkBothInt(t1, t2, "/");  return IntType.ONLY; }
        public JamType forOpLessThan()         { checkBothInt(t1, t2, "<");  return BoolType.ONLY; }
        public JamType forOpGreaterThan()      { checkBothInt(t1, t2, ">");  return BoolType.ONLY; }
        public JamType forOpLessThanEquals()   { checkBothInt(t1, t2, "<="); return BoolType.ONLY; }
        public JamType forOpGreaterThanEquals(){ checkBothInt(t1, t2, ">="); return BoolType.ONLY; }
        public JamType forOpAnd() { checkBothBool(t1, t2, "&"); return BoolType.ONLY; }
        public JamType forOpOr()  { checkBothBool(t1, t2, "|"); return BoolType.ONLY; }
        public JamType forOpEquals() {
          if (!t1.equals(t2))
            throw new TypeException("= requires both operands to have the same type, got " + t1 + " and " + t2);
          return BoolType.ONLY;
        }
        public JamType forOpNotEquals() {
          if (!t1.equals(t2))
            throw new TypeException("!= requires both operands to have the same type, got " + t1 + " and " + t2);
          return BoolType.ONLY;
        }
        public JamType forOpGets() {
          if (!(t1 instanceof RefType))
            throw new TypeException("<- requires a ref on the left, got " + t1);
          JamType inner = ((RefType) t1).elemType();
          if (!t2.equals(inner))
            throw new TypeException("<- type mismatch: ref " + inner + " but assigned " + t2);
          return UnitType.ONLY;
        }
      });
    }

    public JamType forApp(App a) {
      AST rator = a.rator();
      final AST[] args = a.args();

      // Primitive function application
      if (rator instanceof PrimFun) {
        return checkPrimApp((PrimFun) rator, args);
      }

      // User-defined function application
      JamType ratorType = rator.accept(this);
      if (!(ratorType instanceof FunType))
        throw new TypeException("Applied expression has non-function type " + ratorType);
      FunType funType = (FunType) ratorType;
      JamType[] params = funType.params();
      if (params.length != args.length)
        throw new TypeException("Function expects " + params.length + " argument(s), given " + args.length);
      for (int i = 0; i < params.length; i++) {
        JamType argType = args[i].accept(this);
        if (!argType.equals(params[i]))
          throw new TypeException("Argument " + i + " has type " + argType +
                                  " but parameter requires " + params[i]);
      }
      return funType.result();
    }

    public JamType forMap(Map m) {
      JamType[] paramTypes = m.types();
      Variable[] vars = m.vars();
      if (paramTypes == null)
        throw new TypeException("map parameters must have type annotations in Typed Jam");
      TypeCheckVisitor newVisitor = extend(vars, paramTypes);
      JamType bodyType = m.body().accept(newVisitor);
      return new FunType(paramTypes, bodyType);
    }

    public JamType forIf(If i) {
      JamType testType = i.test().accept(this);
      if (!(testType instanceof BoolType))
        throw new TypeException("if condition must be bool, got " + testType);
      JamType conseqType = i.conseq().accept(this);
      JamType altType = i.alt().accept(this);
      if (!conseqType.equals(altType))
        throw new TypeException("if branches have different types: " + conseqType + " and " + altType);
      return conseqType;
    }

    public JamType forLet(Let l) {
      Def[] defs = l.defs();
      int n = defs.length;

      // Gather declared types for all variables (for recursive let)
      Variable[] allVars = new Variable[n];
      JamType[] allTypes = new JamType[n];
      for (int i = 0; i < n; i++) {
        allVars[i] = defs[i].lhs();
        allTypes[i] = defs[i].type();
        if (allTypes[i] == null)
          throw new TypeException("Missing type annotation for " + allVars[i]);
      }

      // Extend the environment with all declared types (supports mutual recursion)
      TypeCheckVisitor newVisitor = extend(allVars, allTypes);

      // Check each rhs against its declared type
      for (int i = 0; i < n; i++) {
        JamType rhsType = defs[i].rhs().accept(newVisitor);
        if (!rhsType.equals(allTypes[i]))
          throw new TypeException("let binding `" + allVars[i] + "' declared as " +
                                  allTypes[i] + " but right-hand side has type " + rhsType);
      }

      return l.body().accept(newVisitor);
    }

    public JamType forBlock(Block b) {
      AST[] exps = b.exps();
      JamType last = null;
      for (AST exp : exps) last = exp.accept(this);
      return last;
    }

    /* ----- Helpers ----- */

    private void checkBothInt(JamType t1, JamType t2, String op) {
      if (!(t1 instanceof IntType) || !(t2 instanceof IntType))
        throw new TypeException("`" + op + "' requires both operands to be int, got " +
                                t1 + " and " + t2);
    }

    private void checkBothBool(JamType t1, JamType t2, String op) {
      if (!(t1 instanceof BoolType) || !(t2 instanceof BoolType))
        throw new TypeException("`" + op + "' requires both operands to be bool, got " +
                                t1 + " and " + t2);
    }

    /** Type-checks a primitive function application. */
    private JamType checkPrimApp(PrimFun prim, final AST[] args) {
      return prim.accept(new PrimFunVisitor<JamType>() {
        public JamType forConsPrim() {
          if (args.length != 2)
            throw new TypeException("cons expects 2 arguments, given " + args.length);
          JamType elemType = args[0].accept(TypeCheckVisitor.this);
          JamType listType = args[1].accept(TypeCheckVisitor.this);
          if (!(listType instanceof ListType))
            throw new TypeException("Second argument to cons must be a list, got " + listType);
          JamType expected = ((ListType) listType).elemType();
          if (!elemType.equals(expected))
            throw new TypeException("cons: element type mismatch: got " + elemType +
                                    " but list has element type " + expected);
          return listType;
        }
        public JamType forFirstPrim() {
          if (args.length != 1)
            throw new TypeException("first expects 1 argument, given " + args.length);
          JamType t = args[0].accept(TypeCheckVisitor.this);
          if (!(t instanceof ListType))
            throw new TypeException("first: argument must be a list, got " + t);
          return ((ListType) t).elemType();
        }
        public JamType forRestPrim() {
          if (args.length != 1)
            throw new TypeException("rest expects 1 argument, given " + args.length);
          JamType t = args[0].accept(TypeCheckVisitor.this);
          if (!(t instanceof ListType))
            throw new TypeException("rest: argument must be a list, got " + t);
          return t;
        }
        public JamType forEmptyPPrim() {
          if (args.length != 1)
            throw new TypeException("empty? expects 1 argument, given " + args.length);
          JamType t = args[0].accept(TypeCheckVisitor.this);
          if (!(t instanceof ListType))
            throw new TypeException("empty?: argument must be a list, got " + t);
          return BoolType.ONLY;
        }
        public JamType forConsPPrim() {
          if (args.length != 1)
            throw new TypeException("cons? expects 1 argument, given " + args.length);
          JamType t = args[0].accept(TypeCheckVisitor.this);
          if (!(t instanceof ListType))
            throw new TypeException("cons?: argument must be a list, got " + t);
          return BoolType.ONLY;
        }
        // These should have been rejected at parse time, but guard anyway:
        public JamType forFunctionPPrim() {
          throw new TypeException("function? is not available in Typed Jam");
        }
        public JamType forNumberPPrim() {
          throw new TypeException("number? is not available in Typed Jam");
        }
        public JamType forListPPrim() {
          throw new TypeException("list? is not available in Typed Jam");
        }
        public JamType forRefPPrim() {
          throw new TypeException("ref? is not available in Typed Jam");
        }
        public JamType forArityPrim() {
          throw new TypeException("arity is not available in Typed Jam");
        }
      });
    }
  }

  /* ================================================================
   * Evaluation machinery (internal)
   * ================================================================ */

  /** Binding policy interface. */
  interface BindingPolicy {
    Binding newBinding(Variable var, AST ast, EvalVisitor ev);
    Binding newDummyBinding(Variable var);
  }

  /** Cons policy interface. */
  interface ConsPolicy {
    JamVal evalCons(AST[] args, EvalVisitor ev);
  }

  /** Call-by-value binding. */
  static class ValueBinding extends Binding {
    ValueBinding(Variable v, JamVal jv) { super(v, jv); }
    public JamVal value() {
      if (value == null) illegalForwardReference(var());
      return value;
    }
    public void setBinding(Suspension s) { value = s.eval(); }
    public String toString() { return "[" + var + ", " + value + "]"; }
  }

  /** Call-by-name binding. */
  static class NameBinding extends Binding {
    protected Suspension susp;
    NameBinding(Variable v, Suspension s) { super(v, null); susp = s; }
    public JamVal value() { return (susp == null) ? illegalForwardReference(var()) : susp.eval(); }
    public void setBinding(Suspension s) { susp = s; }
    public String toString() { return "[" + var + ", " + susp + "]"; }
  }

  /** Call-by-need binding. */
  static class NeedBinding extends NameBinding {
    NeedBinding(Variable v, Suspension s) { super(v, s); }
    public JamVal value() {
      if (value == null) {
        if (susp == null) illegalForwardReference(var());
        else { value = susp.eval(); susp = null; }
      }
      return value;
    }
    public void setBinding(AST exp, EvalVisitor ev) { susp = new ConcreteSuspension(exp, ev); value = null; }
    public String toString() { return "[" + var + ", " + value + ", " + susp + "]"; }
  }

  static JamVal illegalForwardReference(Variable v) {
    throw new EvalException("Attempt to evaluate variable " + v + " bound to null (illegal forward reference)");
  }

  static final BindingPolicy CALL_BY_VALUE = new BindingPolicy() {
    public Binding newBinding(Variable var, AST arg, EvalVisitor ev) {
      return new ValueBinding(var, arg.accept(ev));
    }
    public Binding newDummyBinding(Variable var) { return new ValueBinding(var, null); }
  };

  static final BindingPolicy CALL_BY_NEED = new BindingPolicy() {
    public Binding newBinding(Variable var, AST arg, EvalVisitor ev) {
      return new NeedBinding(var, new ConcreteSuspension(arg, ev));
    }
    public Binding newDummyBinding(Variable var) { return new NeedBinding(var, null); }
  };

  /** Concrete suspension (unevaluated expression + evaluator). */
  static class ConcreteSuspension implements Suspension {
    private AST exp;
    private EvalVisitor ev;
    ConcreteSuspension(AST a, EvalVisitor e) { exp = a; ev = e; }
    AST exp() { return exp; }
    EvalVisitor ev() { return ev; }
    void putEv(EvalVisitor e) { ev = e; }
    public JamVal eval() { return exp.accept(ev); }
    public String toString() { return "<" + exp + ", " + ev + ">"; }
  }

  /** Lazy cons (call-by-need). */
  static class JamLazyNeedCons extends JamCons {
    private Suspension firstSusp;
    private Suspension restSusp;
    JamLazyNeedCons(AST f, AST r, EvalVisitor ev) {
      super(null, null);
      firstSusp = new ConcreteSuspension(f, ev);
      restSusp  = new ConcreteSuspension(r, ev);
    }
    public JamVal first() {
      if (first == null) { first = firstSusp.eval(); firstSusp = null; }
      return first;
    }
    public JamList rest() {
      if (rest == null) { rest = checkList(restSusp.eval()); restSusp = null; }
      return (JamList) rest;
    }
  }

  /** Eager cons policy. */
  static final ConsPolicy EAGER = new ConsPolicy() {
    public JamVal evalCons(AST[] args, EvalVisitor ev) {
      JamVal val0 = args[0].accept(ev);
      JamVal val1 = args[1].accept(ev);
      if (val1 instanceof JamList) return new JamCons(val0, (JamList) val1);
      throw new EvalException("Second argument " + val1 + " to `cons' is not a JamList");
    }
  };

  /** Call-by-need lazy cons policy. */
  static final ConsPolicy LAZYNEED = new ConsPolicy() {
    public JamVal evalCons(AST[] args, EvalVisitor ev) { return new JamLazyNeedCons(args[0], args[1], ev); }
  };

  /** Value-value evaluator (eager binding + eager cons). */
  static final ASTVisitor<JamVal> valueValueVisitor = new EvalVisitor(CALL_BY_VALUE, EAGER);

  /** Value-need evaluator (eager binding + lazy-need cons). */
  static final ASTVisitor<JamVal> valueNeedVisitor  = new EvalVisitor(CALL_BY_VALUE, LAZYNEED);

  /** Primary evaluation visitor. */
  static class EvalVisitor implements ASTVisitor<JamVal> {

    PureList<Binding> env;
    BindingPolicy bindingPolicy;
    ConsPolicy consPolicy;

    private EvalVisitor(PureList<Binding> e, BindingPolicy bp, ConsPolicy cp) {
      env = e; bindingPolicy = bp; consPolicy = cp;
    }

    EvalVisitor(BindingPolicy bp, ConsPolicy cp) { this(new Empty<Binding>(), bp, cp); }

    EvalVisitor newEvalVisitor(PureList<Binding> env) {
      return new EvalVisitor(env, bindingPolicy, consPolicy);
    }

    PureList<Binding> env() { return env; }

    public JamVal forBoolConstant(BoolConstant b) { return b; }
    public JamVal forIntConstant(IntConstant i)   { return i; }
    public JamVal forEmptyConstant(EmptyConstant n) { return JamEmpty.ONLY; }

    public JamVal forVariable(Variable v) {
      Binding match = env.accept(new LookupVisitor<Binding>(v));
      if (match == null) throw new EvalException("variable " + v + " is unbound");
      return match.value();
    }

    public JamVal forPrimFun(PrimFun f) { return f; }

    public JamVal forUnOpApp(UnOpApp u) {
      return u.rator().accept(new UnOpEvaluator(u.arg().accept(this)));
    }

    public JamVal forBinOpApp(BinOpApp b) {
      return b.rator().accept(new BinOpEvaluator(b.arg1(), b.arg2()));
    }

    public JamVal forApp(App a) {
      JamVal rator = a.rator().accept(this);
      if (rator instanceof JamFun)
        return ((JamFun) rator).accept(new FunEvaluator(a.args()));
      throw new EvalException(rator + " is not a valid function");
    }

    public JamVal forMap(Map m) { return new JamClosure(m, env); }

    public JamVal forIf(If i) {
      JamVal test = i.test().accept(this);
      if (!(test instanceof BoolConstant)) throw new EvalException("non-Boolean test in if");
      if (test == BoolConstant.TRUE) return i.conseq().accept(this);
      return i.alt().accept(this);
    }

    public JamVal forBlock(Block b) {
      AST[] exps = b.exps();
      JamVal result = null;
      for (AST exp : exps) result = exp.accept(this);
      return result;
    }

    public JamVal forLet(Let l) {
      Variable[] vars = l.vars();
      AST[] exps = l.exps();
      int n = vars.length;
      PureList<Binding> newEnv = env();
      Binding[] bindings = new Binding[n];
      for (int i = 0; i < n; i++) {
        bindings[i] = bindingPolicy.newDummyBinding(vars[i]);
        newEnv = newEnv.cons(bindings[i]);
      }
      EvalVisitor newEV = newEvalVisitor(newEnv);
      for (int i = 0; i < n; i++) {
        bindings[i].setBinding(new ConcreteSuspension(exps[i], newEV));
      }
      return l.body().accept(newEV);
    }

    /* ----- Inner classes for evaluation ----- */

    class FunEvaluator implements JamFunVisitor<JamVal> {
      AST[] args;
      FunEvaluator(AST[] asts) { args = asts; }

      PrimFunVisitor<JamVal> primEvaluator = new PrimFunVisitor<JamVal>() {
        private JamVal[] evalArgs() {
          JamVal[] vals = new JamVal[args.length];
          for (int i = 0; i < args.length; i++) vals[i] = args[i].accept(EvalVisitor.this);
          return vals;
        }
        private void primFunError(String fn) {
          throw new EvalException("Primitive `" + fn + "' applied to " + args.length + " arguments");
        }
        private JamCons evalJamConsArg(AST arg, String fun) {
          JamVal val = arg.accept(EvalVisitor.this);
          if (val instanceof JamCons) return (JamCons) val;
          throw new EvalException("Primitive `" + fun + "' applied to non-cons " + val);
        }

        public JamVal forFunctionPPrim() {
          JamVal[] vals = evalArgs();
          if (vals.length != 1) primFunError("function?");
          return BoolConstant.toBoolConstant(vals[0] instanceof JamFun);
        }
        public JamVal forNumberPPrim() {
          JamVal[] vals = evalArgs();
          if (vals.length != 1) primFunError("number?");
          return BoolConstant.toBoolConstant(vals[0] instanceof IntConstant);
        }
        public JamVal forListPPrim() {
          JamVal[] vals = evalArgs();
          if (vals.length != 1) primFunError("list?");
          return BoolConstant.toBoolConstant(vals[0] instanceof JamList);
        }
        public JamVal forConsPPrim() {
          JamVal[] vals = evalArgs();
          if (vals.length != 1) primFunError("cons?");
          return BoolConstant.toBoolConstant(vals[0] instanceof JamCons);
        }
        public JamVal forEmptyPPrim() {
          JamVal[] vals = evalArgs();
          if (vals.length != 1) primFunError("empty?");
          return BoolConstant.toBoolConstant(vals[0] instanceof JamEmpty);
        }
        public JamVal forRefPPrim() {
          JamVal[] vals = evalArgs();
          if (vals.length != 1) primFunError("ref?");
          return BoolConstant.toBoolConstant(vals[0] instanceof JamRef);
        }
        public JamVal forConsPrim() {
          if (args.length != 2) primFunError("cons");
          return consPolicy.evalCons(args, EvalVisitor.this);
        }
        public JamVal forArityPrim() {
          JamVal[] vals = evalArgs();
          if (vals.length != 1) primFunError("arity");
          if (!(vals[0] instanceof JamFun)) throw new EvalException("arity applied to non-function");
          return ((JamFun) vals[0]).accept(new JamFunVisitor<IntConstant>() {
            public IntConstant forJamClosure(JamClosure jc) { return new IntConstant(jc.code().vars().length); }
            public IntConstant forPrimFun(PrimFun jpf) { return new IntConstant(jpf instanceof ConsPrim ? 2 : 1); }
          });
        }
        public JamVal forFirstPrim() {
          if (args.length != 1) primFunError("first");
          return evalJamConsArg(args[0], "first").first();
        }
        public JamVal forRestPrim() {
          if (args.length != 1) primFunError("rest");
          return evalJamConsArg(args[0], "rest").rest();
        }
      };

      public JamVal forJamClosure(JamClosure closure) {
        Map map = closure.code();
        Variable[] vars = map.vars();
        int n = args.length;
        if (vars.length != n) throw new EvalException("closure applied to " + n + " arguments");
        PureList<Binding> newEnv = closure.env();
        for (int i = 0; i < n; i++) {
          newEnv = newEnv.cons(bindingPolicy.newBinding(vars[i], args[i], EvalVisitor.this));
        }
        return map.body().accept(newEvalVisitor(newEnv));
      }

      public JamVal forPrimFun(PrimFun primFun) { return primFun.accept(primEvaluator); }
    }

    static class UnOpEvaluator implements UnOpVisitor<JamVal> {
      private JamVal val;
      UnOpEvaluator(JamVal jv) { val = jv; }

      private IntConstant checkInteger(String op) {
        if (val instanceof IntConstant) return (IntConstant) val;
        throw new EvalException("Unary `" + op + "' applied to non-integer " + val);
      }
      private BoolConstant checkBoolean(String op) {
        if (val instanceof BoolConstant) return (BoolConstant) val;
        throw new EvalException("Unary `" + op + "' applied to non-boolean " + val);
      }
      private JamRef checkRef(String op) {
        if (val instanceof JamRef) return (JamRef) val;
        throw new EvalException("Unary `" + op + "' applied to non-ref " + val);
      }

      public JamVal forUnOpPlus()  { return checkInteger("+"); }
      public JamVal forUnOpMinus() { return new IntConstant(-checkInteger("-").value()); }
      public JamVal forOpTilde()   { return checkBoolean("~").not(); }
      public JamVal forOpBang()    { return checkRef("!").value(); }
      public JamVal forOpRef()     { return new JamRef(val); }
    }

    class BinOpEvaluator implements BinOpVisitor<JamVal> {
      private AST arg1, arg2;
      BinOpEvaluator(AST a1, AST a2) { arg1 = a1; arg2 = a2; }

      private IntConstant evalIntegerArg(AST arg, String b) {
        JamVal val = arg.accept(EvalVisitor.this);
        if (val instanceof IntConstant) return (IntConstant) val;
        throw new EvalException("Binary `" + b + "' applied to non-integer " + val);
      }
      private BoolConstant evalBooleanArg(AST arg, String b) {
        JamVal val = arg.accept(EvalVisitor.this);
        if (val instanceof BoolConstant) return (BoolConstant) val;
        throw new EvalException("Binary `" + b + "' applied to non-boolean " + val);
      }

      public JamVal forBinOpPlus()  { return new IntConstant(evalIntegerArg(arg1,"+").value() + evalIntegerArg(arg2,"+").value()); }
      public JamVal forBinOpMinus() { return new IntConstant(evalIntegerArg(arg1,"-").value() - evalIntegerArg(arg2,"-").value()); }
      public JamVal forOpTimes()    { return new IntConstant(evalIntegerArg(arg1,"*").value() * evalIntegerArg(arg2,"*").value()); }
      public JamVal forOpDivide() {
        int d = evalIntegerArg(arg2,"/").value();
        if (d == 0) throw new EvalException("Division by zero");
        return new IntConstant(evalIntegerArg(arg1,"/").value() / d);
      }
      public JamVal forOpEquals()         { return BoolConstant.toBoolConstant(arg1.accept(EvalVisitor.this).equals(arg2.accept(EvalVisitor.this))); }
      public JamVal forOpNotEquals()      { return BoolConstant.toBoolConstant(!arg1.accept(EvalVisitor.this).equals(arg2.accept(EvalVisitor.this))); }
      public JamVal forOpLessThan()       { return BoolConstant.toBoolConstant(evalIntegerArg(arg1,"<").value() < evalIntegerArg(arg2,"<").value()); }
      public JamVal forOpGreaterThan()    { return BoolConstant.toBoolConstant(evalIntegerArg(arg1,">").value() > evalIntegerArg(arg2,">").value()); }
      public JamVal forOpLessThanEquals() { return BoolConstant.toBoolConstant(evalIntegerArg(arg1,"<=").value() <= evalIntegerArg(arg2,"<=").value()); }
      public JamVal forOpGreaterThanEquals() { return BoolConstant.toBoolConstant(evalIntegerArg(arg1,">=").value() >= evalIntegerArg(arg2,">=").value()); }
      public JamVal forOpAnd() {
        BoolConstant b1 = evalBooleanArg(arg1,"&");
        if (b1 == BoolConstant.FALSE) return BoolConstant.FALSE;
        return evalBooleanArg(arg2,"&");
      }
      public JamVal forOpOr() {
        BoolConstant b1 = evalBooleanArg(arg1,"|");
        if (b1 == BoolConstant.TRUE) return BoolConstant.TRUE;
        return evalBooleanArg(arg2,"|");
      }
      public JamVal forOpGets() {
        JamVal v1 = arg1.accept(EvalVisitor.this);
        if (!(v1 instanceof JamRef)) throw new EvalException("<- applied to non-ref " + v1);
        JamVal v2 = arg2.accept(EvalVisitor.this);
        ((JamRef) v1).setValue(v2);
        return JamUnit.ONLY;
      }
    }
  }
}
